use gnosis_frf::prelude::*;
use serde::{Deserialize, Serialize};
use std::collections::HashMap;

const UINT32_MAX: f64 = 4_294_967_296.0;

#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
#[serde(rename_all = "camelCase")]
pub struct SyntheticTrackBatchInput {
    pub track: String,
    pub start_tick: u64,
    pub tick_count: u32,
    pub shard_index: u32,
    pub population_count: u32,
    pub rng_state: u32,
}

#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
#[serde(rename_all = "camelCase")]
pub struct SyntheticTrackBatchOutput {
    pub rng_state: u32,
    pub score_delta: f64,
    pub confidence_sum_delta: f64,
    pub sample_delta: u32,
    pub metric_deltas: HashMap<String, f64>,
    pub theorem_deltas: HashMap<String, u64>,
    pub warnings: Vec<String>,
}

#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
#[serde(rename_all = "camelCase")]
pub struct SyntheticShardBatchInput {
    pub tracks: Vec<String>,
    pub start_tick: u64,
    pub tick_count: u32,
    pub shard_index: u32,
    pub population_count: u32,
    pub rng_state: u32,
}

#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
#[serde(rename_all = "camelCase")]
pub struct SyntheticShardTrackDelta {
    pub track: String,
    pub score_delta: f64,
    pub confidence_sum_delta: f64,
    pub sample_delta: u32,
    pub metric_deltas: HashMap<String, f64>,
    pub theorem_deltas: HashMap<String, u64>,
    pub warnings: Vec<String>,
}

#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
#[serde(rename_all = "camelCase")]
pub struct SyntheticShardBatchOutput {
    pub rng_state: u32,
    pub track_deltas: Vec<SyntheticShardTrackDelta>,
}

#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
#[serde(rename_all = "camelCase")]
pub struct SyntheticMeshShardInput {
    pub tracks: Vec<String>,
    pub start_tick: u64,
    pub tick_count: u32,
    pub shard_index: u32,
    pub population_count: u32,
    pub rng_state: u32,
}

#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
#[serde(rename_all = "camelCase")]
pub struct SyntheticMeshBatchInput {
    pub shards: Vec<SyntheticMeshShardInput>,
}

#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
#[serde(rename_all = "camelCase")]
pub struct SyntheticMeshShardOutput {
    pub shard_index: u32,
    pub rng_state: u32,
    pub track_deltas: Vec<SyntheticShardTrackDelta>,
}

#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
#[serde(rename_all = "camelCase")]
pub struct SyntheticMeshBatchOutput {
    pub shard_outputs: Vec<SyntheticMeshShardOutput>,
}

#[inline(always)]
fn next_rng(state: u32) -> u32 {
    state.wrapping_mul(1_664_525).wrapping_add(1_013_904_223)
}

#[inline(always)]
fn add_metric(metrics: &mut HashMap<String, f64>, name: &str, delta: f64) {
    if delta == 0.0 {
        return;
    }
    let entry = metrics.entry(name.to_string()).or_insert(0.0);
    *entry += delta;
}

#[inline(always)]
fn add_theorem(theorems: &mut HashMap<String, u64>, name: &str, delta: u64) {
    if delta == 0 {
        return;
    }
    let entry = theorems.entry(name.to_string()).or_insert(0);
    *entry += delta;
}

pub fn run_synthetic_track_batch(input: &SyntheticTrackBatchInput) -> SyntheticTrackBatchOutput {
    let mut rng_state = input.rng_state;
    let mut score_delta = 0.0;
    let mut confidence_sum_delta = 0.0;
    let mut metric_deltas = HashMap::new();
    let mut theorem_deltas = HashMap::new();
    let mut warnings = Vec::new();
    let pop_scale = f64::max(1.0, ((input.population_count as f64) + 1.0).log10());

    match input.track.as_str() {
        "affective" => {
            let mut empathy_forecast_sum = 0.0;
            let mut affect_volatility_sum = 0.0;
            let mut intervention_sensitivity_sum = 0.0;
            let mut intervention_theorem_count: u64 = 0;
            let mut volatility_theorem_count: u64 = 0;

            for _ in 0..input.tick_count {
                rng_state = next_rng(rng_state);
                let u = (rng_state as f64) / UINT32_MAX;
                let centered = u * 2.0 - 1.0;
                let affect_volatility = centered.abs();
                let empathy_forecast = 0.45 + u * 0.5;
                let intervention_sensitivity = 1.0 - affect_volatility * 0.7;

                empathy_forecast_sum += empathy_forecast;
                affect_volatility_sum += affect_volatility;
                intervention_sensitivity_sum += intervention_sensitivity;
                score_delta +=
                    (empathy_forecast * 0.55 + intervention_sensitivity * 0.45) * pop_scale;
                confidence_sum_delta += 0.52 + (1.0 - affect_volatility) * 0.45;

                if intervention_sensitivity > 0.82 {
                    intervention_theorem_count += 1;
                }
                if affect_volatility > 0.93 {
                    volatility_theorem_count += 1;
                }
            }

            add_metric(&mut metric_deltas, "empathyForecast", empathy_forecast_sum);
            add_metric(
                &mut metric_deltas,
                "affectVolatility",
                affect_volatility_sum,
            );
            add_metric(
                &mut metric_deltas,
                "interventionSensitivity",
                intervention_sensitivity_sum,
            );
            add_theorem(
                &mut theorem_deltas,
                "affective.empathy_forecast",
                input.tick_count as u64,
            );
            add_theorem(
                &mut theorem_deltas,
                "affective.intervention_sensitivity",
                intervention_theorem_count,
            );
            add_theorem(
                &mut theorem_deltas,
                "affective.volatility_gate",
                volatility_theorem_count,
            );
            if volatility_theorem_count > 0 {
                warnings.push("Affective volatility exceeded calibrated gate".to_string());
            }
        }
        "abm" => {
            let mut contagion_wave_sum = 0.0;
            let mut panic_index_sum = 0.0;
            let mut spending_shift_sum = 0.0;
            let mut panic_theorem_count: u64 = 0;
            let mut spending_theorem_count: u64 = 0;
            let mut warning_hit = false;
            let mut phase17 = ((input.start_tick + input.shard_index as u64) % 17) as u32;

            for _ in 0..input.tick_count {
                rng_state = next_rng(rng_state);
                let u = (rng_state as f64) / UINT32_MAX;
                let contagion_wave = 0.25 + u * 0.75;
                let phase_scale = 0.8 + (phase17 as f64) / 20.0;
                let raw_panic = contagion_wave * phase_scale;
                let panic_index = if raw_panic > 1.0 { 1.0 } else { raw_panic };
                let spending_shift = (0.4 + (1.0 - u) * 0.6) * pop_scale;
                let confidence_offset = (0.5 - u).abs();

                contagion_wave_sum += contagion_wave;
                panic_index_sum += panic_index;
                spending_shift_sum += spending_shift;
                score_delta +=
                    (1.0 - panic_index) * 0.4 + contagion_wave * 0.2 + spending_shift * 0.4;
                confidence_sum_delta += 0.48 + (1.0 - confidence_offset) * 0.5;

                if panic_index > 0.78 {
                    panic_theorem_count += 1;
                }
                if spending_shift > 1.3 {
                    spending_theorem_count += 1;
                }
                if panic_index > 0.95 {
                    warning_hit = true;
                }

                phase17 += 1;
                if phase17 == 17 {
                    phase17 = 0;
                }
            }

            add_metric(&mut metric_deltas, "contagionWave", contagion_wave_sum);
            add_metric(&mut metric_deltas, "panicIndex", panic_index_sum);
            add_metric(&mut metric_deltas, "spendingShift", spending_shift_sum);
            add_theorem(
                &mut theorem_deltas,
                "abm.contagion_wave",
                input.tick_count as u64,
            );
            add_theorem(
                &mut theorem_deltas,
                "abm.market_panic_stress",
                panic_theorem_count,
            );
            add_theorem(
                &mut theorem_deltas,
                "abm.spending_reallocation",
                spending_theorem_count,
            );
            if warning_hit {
                warnings.push("ABM panic index entered critical zone".to_string());
            }
        }
        "neural" => {
            let mut signal_propagation_sum = 0.0;
            let mut uncertainty_envelope_sum = 0.0;
            let mut treatment_projection_sum = 0.0;
            let mut uncertainty_theorem_count: u64 = 0;
            let mut treatment_theorem_count: u64 = 0;
            let mut warning_hit = false;

            for _ in 0..input.tick_count {
                rng_state = next_rng(rng_state);
                let u = (rng_state as f64) / UINT32_MAX;
                let centered = u * 2.0 - 1.0;
                let centered_abs = centered.abs();
                let signal_propagation = 0.2 + u * 0.8;
                let uncertainty_raw = centered_abs * 1.2;
                let uncertainty_envelope = if uncertainty_raw > 1.0 {
                    1.0
                } else {
                    uncertainty_raw
                };
                let treatment_projection = signal_propagation * (1.0 - uncertainty_envelope);

                signal_propagation_sum += signal_propagation;
                uncertainty_envelope_sum += uncertainty_envelope;
                treatment_projection_sum += treatment_projection;
                score_delta += signal_propagation * 0.5 + treatment_projection * 0.5;
                confidence_sum_delta += 0.35 + (1.0 - uncertainty_envelope) * 0.6;

                if uncertainty_envelope > 0.6 {
                    uncertainty_theorem_count += 1;
                }
                if treatment_projection > 0.5 {
                    treatment_theorem_count += 1;
                }
                if uncertainty_envelope > 0.9 {
                    warning_hit = true;
                }
            }

            add_metric(
                &mut metric_deltas,
                "signalPropagation",
                signal_propagation_sum,
            );
            add_metric(
                &mut metric_deltas,
                "uncertaintyEnvelope",
                uncertainty_envelope_sum,
            );
            add_metric(
                &mut metric_deltas,
                "treatmentProjection",
                treatment_projection_sum,
            );
            add_theorem(
                &mut theorem_deltas,
                "neural.signal_propagation",
                input.tick_count as u64,
            );
            add_theorem(
                &mut theorem_deltas,
                "neural.uncertainty_envelope",
                uncertainty_theorem_count,
            );
            add_theorem(
                &mut theorem_deltas,
                "neural.treatment_response_projection",
                treatment_theorem_count,
            );
            if warning_hit {
                warnings
                    .push("Neural uncertainty envelope exceeds high-fidelity bound".to_string());
            }
        }
        "syntheticUx" => {
            let mut confusion_risk_sum = 0.0;
            let mut friction_score_sum = 0.0;
            let mut churn_hazard_sum = 0.0;
            let mut friction_theorem_count: u64 = 0;
            let mut churn_theorem_count: u64 = 0;
            let mut warning_hit = false;
            let mut phase9 = ((input.start_tick + input.shard_index as u64) % 9) as u32;

            for _ in 0..input.tick_count {
                rng_state = next_rng(rng_state);
                let u = (rng_state as f64) / UINT32_MAX;
                let confusion_risk = 0.1 + u * 0.9;
                let friction_factor = 0.6 + (phase9 as f64) / 20.0;
                let raw_friction = 1.0 - confusion_risk * friction_factor;
                let friction_score = if raw_friction < 0.0 {
                    0.0
                } else {
                    raw_friction
                };
                let raw_churn = confusion_risk * (1.1 - friction_score * 0.6);
                let churn_hazard = if raw_churn > 1.0 { 1.0 } else { raw_churn };

                confusion_risk_sum += confusion_risk;
                friction_score_sum += friction_score;
                churn_hazard_sum += churn_hazard;
                score_delta += (1.0 - churn_hazard) * 0.55 + friction_score * 0.45;
                confidence_sum_delta += 0.42 + friction_score * 0.5;

                if friction_score < 0.35 {
                    friction_theorem_count += 1;
                }
                if churn_hazard > 0.65 {
                    churn_theorem_count += 1;
                }
                if churn_hazard > 0.9 {
                    warning_hit = true;
                }

                phase9 += 1;
                if phase9 == 9 {
                    phase9 = 0;
                }
            }

            add_metric(&mut metric_deltas, "confusionRisk", confusion_risk_sum);
            add_metric(&mut metric_deltas, "frictionScore", friction_score_sum);
            add_metric(&mut metric_deltas, "churnHazard", churn_hazard_sum);
            add_theorem(
                &mut theorem_deltas,
                "ux.confusion_predictor",
                input.tick_count as u64,
            );
            add_theorem(
                &mut theorem_deltas,
                "ux.friction_gate",
                friction_theorem_count,
            );
            add_theorem(&mut theorem_deltas, "ux.churn_hazard", churn_theorem_count);
            if warning_hit {
                warnings.push("Synthetic UX churn hazard crossed 0.9".to_string());
            }
        }
        _ => {
            warnings.push(format!("Unknown synthetic track '{}'", input.track));
        }
    }

    SyntheticTrackBatchOutput {
        rng_state,
        score_delta,
        confidence_sum_delta,
        sample_delta: input.tick_count,
        metric_deltas,
        theorem_deltas,
        warnings,
    }
}

pub fn run_synthetic_shard_batch(input: &SyntheticShardBatchInput) -> SyntheticShardBatchOutput {
    let mut state = input.rng_state;
    let mut track_deltas = Vec::with_capacity(input.tracks.len());
    for track in &input.tracks {
        let track_input = SyntheticTrackBatchInput {
            track: track.clone(),
            start_tick: input.start_tick,
            tick_count: input.tick_count,
            shard_index: input.shard_index,
            population_count: input.population_count,
            rng_state: state,
        };
        let track_output = run_synthetic_track_batch(&track_input);
        state = track_output.rng_state;
        track_deltas.push(SyntheticShardTrackDelta {
            track: track.clone(),
            score_delta: track_output.score_delta,
            confidence_sum_delta: track_output.confidence_sum_delta,
            sample_delta: track_output.sample_delta,
            metric_deltas: track_output.metric_deltas,
            theorem_deltas: track_output.theorem_deltas,
            warnings: track_output.warnings,
        });
    }

    SyntheticShardBatchOutput {
        rng_state: state,
        track_deltas,
    }
}

pub fn run_synthetic_mesh_batch(input: &SyntheticMeshBatchInput) -> SyntheticMeshBatchOutput {
    let shard_outputs = input
        .shards
        .par_iter()
        .map(|shard| {
            let output = run_synthetic_shard_batch(&SyntheticShardBatchInput {
                tracks: shard.tracks.clone(),
                start_tick: shard.start_tick,
                tick_count: shard.tick_count,
                shard_index: shard.shard_index,
                population_count: shard.population_count,
                rng_state: shard.rng_state,
            });
            SyntheticMeshShardOutput {
                shard_index: shard.shard_index,
                rng_state: output.rng_state,
                track_deltas: output.track_deltas,
            }
        })
        .collect();

    SyntheticMeshBatchOutput { shard_outputs }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn fixture_input(track: &str) -> SyntheticTrackBatchInput {
        SyntheticTrackBatchInput {
            track: track.to_string(),
            start_tick: 4_096,
            tick_count: 128,
            shard_index: 7,
            population_count: 5_000,
            rng_state: 0x1234_5678,
        }
    }

    fn assert_track_contract(track: &str, metric_keys: &[&str], base_theorem: &str) {
        let input = fixture_input(track);
        let output = run_synthetic_track_batch(&input);
        let rerun = run_synthetic_track_batch(&input);

        assert_eq!(output, rerun);
        assert_eq!(output.sample_delta, input.tick_count);
        assert!(output.score_delta.is_finite());
        assert!(output.confidence_sum_delta.is_finite());
        assert!(output.score_delta > 0.0);
        assert!(output.confidence_sum_delta > 0.0);
        assert_eq!(
            output
                .theorem_deltas
                .get(base_theorem)
                .copied()
                .unwrap_or(0),
            input.tick_count as u64
        );

        for metric_key in metric_keys {
            assert!(
                output.metric_deltas.contains_key(*metric_key),
                "missing metric key {} for track {}",
                metric_key,
                track
            );
        }
    }

    #[test]
    fn deterministic_output_contracts_hold_for_supported_tracks() {
        assert_track_contract(
            "affective",
            &[
                "empathyForecast",
                "affectVolatility",
                "interventionSensitivity",
            ],
            "affective.empathy_forecast",
        );
        assert_track_contract(
            "abm",
            &["contagionWave", "panicIndex", "spendingShift"],
            "abm.contagion_wave",
        );
        assert_track_contract(
            "neural",
            &[
                "signalPropagation",
                "uncertaintyEnvelope",
                "treatmentProjection",
            ],
            "neural.signal_propagation",
        );
        assert_track_contract(
            "syntheticUx",
            &["confusionRisk", "frictionScore", "churnHazard"],
            "ux.confusion_predictor",
        );
    }

    #[test]
    fn unknown_track_emits_warning_with_no_metric_or_theorem_deltas() {
        let output = run_synthetic_track_batch(&fixture_input("unknown-track"));

        assert_eq!(output.sample_delta, 128);
        assert_eq!(output.metric_deltas.len(), 0);
        assert_eq!(output.theorem_deltas.len(), 0);
        assert_eq!(output.warnings.len(), 1);
        assert!(output.warnings[0].contains("unknown-track"));
    }

    #[test]
    fn zero_tick_batches_stay_stable() {
        let mut input = fixture_input("affective");
        input.tick_count = 0;
        let output = run_synthetic_track_batch(&input);

        assert_eq!(output.sample_delta, 0);
        assert_eq!(output.score_delta, 0.0);
        assert_eq!(output.confidence_sum_delta, 0.0);
        assert_eq!(output.metric_deltas.len(), 0);
        assert_eq!(output.theorem_deltas.len(), 0);
        assert_eq!(output.warnings.len(), 0);
    }

    #[test]
    fn fused_shard_batch_matches_track_batch_chain() {
        let input = SyntheticShardBatchInput {
            tracks: vec![
                "affective".to_string(),
                "abm".to_string(),
                "neural".to_string(),
                "syntheticUx".to_string(),
            ],
            start_tick: 4_096,
            tick_count: 128,
            shard_index: 7,
            population_count: 5_000,
            rng_state: 0x1234_5678,
        };

        let fused = run_synthetic_shard_batch(&input);
        let mut expected_state = input.rng_state;
        let mut expected_deltas = Vec::new();
        for track in &input.tracks {
            let output = run_synthetic_track_batch(&SyntheticTrackBatchInput {
                track: track.clone(),
                start_tick: input.start_tick,
                tick_count: input.tick_count,
                shard_index: input.shard_index,
                population_count: input.population_count,
                rng_state: expected_state,
            });
            expected_state = output.rng_state;
            expected_deltas.push(SyntheticShardTrackDelta {
                track: track.clone(),
                score_delta: output.score_delta,
                confidence_sum_delta: output.confidence_sum_delta,
                sample_delta: output.sample_delta,
                metric_deltas: output.metric_deltas,
                theorem_deltas: output.theorem_deltas,
                warnings: output.warnings,
            });
        }

        assert_eq!(fused.rng_state, expected_state);
        assert_eq!(fused.track_deltas, expected_deltas);
    }

    #[test]
    fn mesh_batch_matches_shard_batch_per_shard() {
        let shards = vec![
            SyntheticMeshShardInput {
                tracks: vec![
                    "affective".to_string(),
                    "abm".to_string(),
                    "neural".to_string(),
                    "syntheticUx".to_string(),
                ],
                start_tick: 4_096,
                tick_count: 128,
                shard_index: 3,
                population_count: 5_000,
                rng_state: 0x1234_5678,
            },
            SyntheticMeshShardInput {
                tracks: vec![
                    "affective".to_string(),
                    "abm".to_string(),
                    "neural".to_string(),
                    "syntheticUx".to_string(),
                ],
                start_tick: 8_192,
                tick_count: 96,
                shard_index: 11,
                population_count: 7_500,
                rng_state: 0x2345_6789,
            },
            SyntheticMeshShardInput {
                tracks: vec![
                    "affective".to_string(),
                    "abm".to_string(),
                    "neural".to_string(),
                    "syntheticUx".to_string(),
                ],
                start_tick: 16_384,
                tick_count: 160,
                shard_index: 29,
                population_count: 12_000,
                rng_state: 0x3456_7890,
            },
        ];
        let mesh_input = SyntheticMeshBatchInput {
            shards: shards.clone(),
        };

        let mesh_output = run_synthetic_mesh_batch(&mesh_input);
        let rerun_output = run_synthetic_mesh_batch(&mesh_input);
        assert_eq!(mesh_output, rerun_output);
        assert_eq!(mesh_output.shard_outputs.len(), shards.len());

        for (index, shard_input) in shards.iter().enumerate() {
            let expected = run_synthetic_shard_batch(&SyntheticShardBatchInput {
                tracks: shard_input.tracks.clone(),
                start_tick: shard_input.start_tick,
                tick_count: shard_input.tick_count,
                shard_index: shard_input.shard_index,
                population_count: shard_input.population_count,
                rng_state: shard_input.rng_state,
            });
            let actual = &mesh_output.shard_outputs[index];
            assert_eq!(actual.shard_index, shard_input.shard_index);
            assert_eq!(actual.rng_state, expected.rng_state);
            assert_eq!(actual.track_deltas, expected.track_deltas);
        }
    }
}
